    "Leg Swings Lateral": { pl: "Wahadło nóg boczne", de: "Beinschwünge seitlich", fr: "Balanciers de jambes latéraux", zh: "腿部侧向摆动" },
    "Sound Reaction Footwork": { pl: "Footwork na sygnał dźwiękowy", de: "Beinarbeit auf Tonsignal", fr: "Jeu de jambes sur signal sonore", zh: "声音反应步法" },
