    "Wszystkie typy rotacji serwów — losowe plasowanie, pełna paleta odbiorów.": { en: "All serve spin types — random placement, full receive repertoire.", de: "Alle Aufschlag-Spin-Typen — zufällige Platzierung, volles Rückschlag-Repertoire.", fr: "Tous types d'effets de service — placement aléatoire, répertoire complet de réception.", zh: "所有发球旋转类型——随机落点，全面接发球技术。" },
    "Chiński pattern 4th ball counter-attack — kontra po flicku przeciwnika.": { en: "Chinese 4th ball counter-attack — counter after opponent's flick.", de: "Chinesischer 4.-Ball-Konterangriff — Konter nach gegnerischem Flip.", fr: "Contre-attaque chinoise 4e balle — contre après le flip de l'adversaire.", zh: "中国第四板反攻——对手拧拉后的反拉。" },
    "Dłuższe serie, mniej odpoczynku — budowanie kondycji i stabilności.": { en: "Longer series, less rest — building fitness and consistency.", de: "Längere Serien, weniger Erholung — Kondition und Konstanz aufbauen.", fr: "Séries plus longues, moins de repos — développer la condition physique et la régularité.", zh: "更长的系列、更少休息——建立体能和稳定性。" },
    "Maksymalna prędkość, losowe rotacje — sprawdzian pod presją.": { en: "Maximum speed, random spins — test under pressure.", de: "Maximale Geschwindigkeit, zufällige Spins — Test unter Druck.", fr: "Vitesse maximale, effets aléatoires — test sous pression.", zh: "最大速度、随机旋转——压力下的测试。" },
